mapper.select:
SELECT COUNT(DISTINCT record_date) AS record_days FROM bookkeeping_records WHERE deleted = 0
AND is_statistics = 1
AND record_date BETWEEN #{startDate} AND #{endDate}

SELECT r.dict_id AS dictId, COUNT(*) AS count, SUM(b.amount) AS amount FROM base_dict_business_relation r JOIN bookkeeping_records b ON r.business_id = b.id WHERE r.business_type = 4001
AND b.record_category in #{item}
AND b.deleted = 0
AND b.is_statistics = 1
AND b.record_date BETWEEN #{startDate} AND #{endDate} GROUP BY r.dict_id ORDER BY count DESC;
